#!/usr/bin/env bash
# generate-pkgbuild.sh — generate PKGBUILD + .SRCINFO for a given version
#
# Usage:
#   bash dist/arch/generate-pkgbuild.sh <version>
#
# Example:
#   bash dist/arch/generate-pkgbuild.sh v0.4.0
#
# Output:
#   Writes PKGBUILD and .SRCINFO to stdout (or to a directory with --out)

set -euo pipefail

if [ $# -lt 1 ]; then
  echo "Usage: $0 <version> [--out <dir>]"
  echo "  version — e.g. v0.4.0"
  echo "  --out   — write files to directory instead of stdout"
  exit 1
fi

VERSION="${1#v}"              # strip leading v: v0.4.0 -> 0.4.0
TAG="v$VERSION"
OUT_DIR=""

shift
while [ $# -gt 0 ]; do
  case "$1" in
    --out) OUT_DIR="$2"; shift 2 ;;
    *) echo "Unknown arg: $1"; exit 1 ;;
  esac
done

# ---- PKGBUILD ----
read -r -d '' PKGBUILD << PKGBUILD_EOF || true
# Maintainer: Anas <anas1412@github>
# Contributor: Anas <anas1412@github>
# Arch User Repository (AUR) package for ytmgo
# https://aur.archlinux.org/packages/ytmgo
# Auto-generated by dist/arch/generate-pkgbuild.sh

pkgname=ytmgo
pkgver=$VERSION
pkgrel=1
pkgdesc="A terminal-based YouTube Music client — search, download, queue, and play music from the keyboard"
arch=('x86_64' 'aarch64')
url="https://github.com/anas1412/ytmgo"
license=('MIT')
depends=('mpv' 'yt-dlp' 'ffmpeg')
makedepends=('go>=1.22')
source=("\$url/archive/v\$pkgver.tar.gz")
sha256sums=('SKIP')

build() {
  cd "\$srcdir/\$pkgname-\$pkgver"
  CGO_ENABLED=0 go build \\
    -ldflags="-s -w -X ytmgo/internal/version.Version=v\$pkgver" \\
    -o ytmgo .
}

check() {
  cd "\$srcdir/\$pkgname-\$pkgver"
  ./ytmgo --version 2>&1 | grep -q "v\$pkgver"
}

package() {
  cd "\$srcdir/\$pkgname-\$pkgver"
  install -Dm755 ytmgo "\$pkgdir/usr/bin/ytmgo"
  install -Dm644 ytmgo-logo.png "\$pkgdir/usr/share/pixmaps/ytmgo.png"
  install -Dm644 /dev/stdin "\$pkgdir/usr/share/applications/ytmgo.desktop" <<EOF
[Desktop Entry]
Type=Application
Name=ytmgo
Comment=YouTube Music from the Terminal
Exec=ytmgo
Icon=ytmgo
Terminal=true
Categories=Audio;Music;Player;
EOF
}
PKGBUILD_EOF

# ---- .SRCINFO ----
read -r -d '' SRCINFO << SRCINFO_EOF || true
pkgbase = ytmgo
	pkgdesc = A terminal-based YouTube Music client — search, download, queue, and play music from the keyboard
	pkgver = $VERSION
	pkgrel = 1
	url = https://github.com/anas1412/ytmgo
	arch = x86_64
	arch = aarch64
	license = MIT
	makedepends = go>=1.22
	depends = mpv
	depends = yt-dlp
	depends = ffmpeg
	source = https://github.com/anas1412/ytmgo/archive/v$VERSION.tar.gz
	sha256sums = SKIP

pkgname = ytmgo
SRCINFO_EOF

# ---- Output ----
if [ -n "$OUT_DIR" ]; then
  mkdir -p "$OUT_DIR"
  echo "$PKGBUILD" > "$OUT_DIR/PKGBUILD"
  echo "$SRCINFO" > "$OUT_DIR/.SRCINFO"
  echo "Generated for v$VERSION:"
  echo "  $OUT_DIR/PKGBUILD"
  echo "  $OUT_DIR/.SRCINFO"
else
  echo "============================================"
  echo " PKGBUILD"
  echo "============================================"
  echo "$PKGBUILD"
  echo ""
  echo "============================================"
  echo " .SRCINFO"
  echo "============================================"
  echo "$SRCINFO"
fi
